using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

[McpServerToolType]
public sealed class WeatherTools
{
    [McpServerTool(Name = "get_forecast", Title = "Get Weather Forecast", ReadOnly = true)]
    [Description("Returns a 7-day weather forecast for the given latitude and longitude.")]
    public async Task<string> GetForecast(
        IHttpClientFactory httpClientFactory,
        [Description("Latitude of the location (e.g. 47.6062)")] double latitude,
        [Description("Longitude of the location (e.g. -122.3321)")] double longitude)
    {
        using var client = httpClientFactory.CreateClient("WeatherApi");

        var url = $"/v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&daily=temperature_2m_max,temperature_2m_min,precipitation_sum"
                + "&timezone=auto&forecast_days=7";

        var response = await client.GetFromJsonAsync<ForecastResponse>(url);

        if (response?.Daily is null)
            return "No forecast data available.";

        var lines = new List<string> { "7-Day Forecast:" };
        for (int i = 0; i < response.Daily.Time.Count; i++)
        {
            lines.Add($"  {response.Daily.Time[i]}: "
                     + $"{response.Daily.TemperatureMin[i]}–{response.Daily.TemperatureMax[i]}°C, "
                     + $"precip {response.Daily.PrecipitationSum[i]} mm");
        }

        return string.Join("\n", lines);
    }

    [McpServerTool(Name = "get_current_weather", Title = "Get Current Weather", ReadOnly = true)]
    [Description("Returns current temperature and wind speed for the given coordinates.")]
    public async Task<string> GetCurrentWeather(
        IHttpClientFactory httpClientFactory,
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        using var client = httpClientFactory.CreateClient("WeatherApi");

        var url = $"/v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        var response = await client.GetFromJsonAsync<CurrentWeatherResponse>(url);

        if (response?.Current is null)
            return "No current weather data available.";

        return $"Current weather: {response.Current.Temperature}°C, "
             + $"wind {response.Current.WindSpeed} km/h";
    }
}

// --- JSON response models ---

public sealed class ForecastResponse
{
    [JsonPropertyName("daily")]
    public DailyData? Daily { get; set; }
}

public sealed class DailyData
{
    [JsonPropertyName("time")]
    public List<string> Time { get; set; } = [];

    [JsonPropertyName("temperature_2m_max")]
    public List<double> TemperatureMax { get; set; } = [];

    [JsonPropertyName("temperature_2m_min")]
    public List<double> TemperatureMin { get; set; } = [];

    [JsonPropertyName("precipitation_sum")]
    public List<double> PrecipitationSum { get; set; } = [];
}

public sealed class CurrentWeatherResponse
{
    [JsonPropertyName("current")]
    public CurrentData? Current { get; set; }
}

public sealed class CurrentData
{
    [JsonPropertyName("temperature_2m")]
    public double Temperature { get; set; }

    [JsonPropertyName("wind_speed_10m")]
    public double WindSpeed { get; set; }
}

